import java.util.logging.Logger;

public class FauxFile {
    private static final Logger LOG = Logger.getLogger(FauxFile.class.getName());
    private static final String CLASS_NAME = "FauxFile";

    private String name;
    private String schema;
    private String type;
    private String revision;

    public FauxFile() {
        this.name = "";
        this.schema = "";
        this.type = "";
        this.revision = "";
    }

    public void setName(String name) {
        this.name = name;
    }

    public String getName() {
        return name;
    }

    public String getType() {
        return type;
    }

    public String toString() {
        return CLASS_NAME + "[name=" + name + ", type=" + type + ", schema=" + schema + ", revision=" + revision + "]";
    }

    public void setRevision(String revision) {
        this.revision = revision;
    }

    public String getSuffixFromType() {
        if (type == null) return "";
        String t = type.toLowerCase();
        switch (t) {
            case "java": return ".java";
            case "python": return ".py";
            case "javascript": case "js": return ".js";
            case "kotlin": return ".kt";
            case "c": return ".c";
            case "cpp": case "c++": return ".cpp";
            case "go": return ".go";
            case "ruby": return ".rb";
            case "scala": return ".scala";
            case "php": return ".php";
            default: return "." + t;
        }
    }

    public void setType(String type) {
        this.type = type;
    }

    public void setSchema(String schema) {
        this.schema = schema;
    }

    public String getSchema() {
        return schema;
    }

    public String getRevision() {
        return revision;
    }
}
